CREATE DATABASE IF NOT EXISTS seim_mantencion CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci; USE seim_mantencion;
SET FOREIGN_KEY_CHECKS=0;
DROP TABLE IF EXISTS audit_logs,origenes_cable,informe_datos,informe_pruebas,informe_materiales,informe_causas_probables,informe_lugares_falla,informe_fallas_enchufe,informe_fallas_chaquetas,informes_cable,cables,marcas_cable,kardex_materiales,recepcion_material_detalle,recepciones_materiales,entrega_material_detalle,entregas_materiales,materiales,categorias_materiales,rol_permiso,permisos,usuarios,roles;
SET FOREIGN_KEY_CHECKS=1;
CREATE TABLE roles(id INT AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(80) NOT NULL UNIQUE,estado ENUM('activo','inactivo') DEFAULT 'activo',created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,deleted_at TIMESTAMP NULL);
CREATE TABLE permisos(id INT AUTO_INCREMENT PRIMARY KEY,modulo VARCHAR(80) NOT NULL,permiso ENUM('ver','crear','editar','eliminar','exportar','imprimir') NOT NULL,UNIQUE KEY uq_perm(modulo,permiso));
CREATE TABLE rol_permiso(rol_id INT NOT NULL,modulo VARCHAR(80) NOT NULL,permiso VARCHAR(20) NOT NULL,permitido TINYINT(1) DEFAULT 1,PRIMARY KEY(rol_id,modulo,permiso),FOREIGN KEY(rol_id) REFERENCES roles(id));
CREATE TABLE usuarios(id INT AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(80) NOT NULL,apellido VARCHAR(80) NOT NULL,usuario VARCHAR(50) NOT NULL UNIQUE,email VARCHAR(120) NOT NULL UNIQUE,telefono VARCHAR(40),cargo VARCHAR(80),area VARCHAR(80),rol_id INT NOT NULL,estado ENUM('activo','inactivo') DEFAULT 'activo',password VARCHAR(255) NOT NULL,created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,deleted_at TIMESTAMP NULL,FOREIGN KEY(rol_id) REFERENCES roles(id),INDEX idx_usuario_estado(estado));
CREATE TABLE categorias_materiales(id INT AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(100) NOT NULL,estado ENUM('activo','inactivo') DEFAULT 'activo',created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,deleted_at TIMESTAMP NULL);
CREATE TABLE materiales(id INT AUTO_INCREMENT PRIMARY KEY,codigo_interno VARCHAR(50) NOT NULL UNIQUE,nombre_material VARCHAR(150) NOT NULL,descripcion TEXT,categoria_id INT,unidad_medida VARCHAR(30) DEFAULT 'un',stock_actual DECIMAL(12,2) DEFAULT 0,stock_minimo DECIMAL(12,2) DEFAULT 0,foto VARCHAR(255),estado ENUM('activo','inactivo') DEFAULT 'activo',created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,deleted_at TIMESTAMP NULL,FOREIGN KEY(categoria_id) REFERENCES categorias_materiales(id),INDEX idx_stock(stock_actual,stock_minimo));
CREATE TABLE entregas_materiales(id INT AUTO_INCREMENT PRIMARY KEY,usuario_receptor_id INT NOT NULL,usuario_entrega_id INT NOT NULL,fecha_entrega DATE NOT NULL,observacion TEXT,estado ENUM('activa','cerrada','anulada') DEFAULT 'activa',created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,FOREIGN KEY(usuario_receptor_id) REFERENCES usuarios(id),FOREIGN KEY(usuario_entrega_id) REFERENCES usuarios(id));
CREATE TABLE entrega_material_detalle(id INT AUTO_INCREMENT PRIMARY KEY,entrega_id INT NOT NULL,material_id INT NOT NULL,cantidad_entregada DECIMAL(12,2) NOT NULL,stock_antes DECIMAL(12,2) NOT NULL,stock_despues DECIMAL(12,2) NOT NULL,cantidad_disponible DECIMAL(12,2) NOT NULL DEFAULT 0,FOREIGN KEY(entrega_id) REFERENCES entregas_materiales(id),FOREIGN KEY(material_id) REFERENCES materiales(id));
CREATE TABLE recepciones_materiales(id INT AUTO_INCREMENT PRIMARY KEY,usuario_devuelve_id INT NOT NULL,usuario_recibe_id INT NOT NULL,fecha_recepcion DATE NOT NULL,observacion TEXT,estado ENUM('registrada','anulada') DEFAULT 'registrada',created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,FOREIGN KEY(usuario_devuelve_id) REFERENCES usuarios(id),FOREIGN KEY(usuario_recibe_id) REFERENCES usuarios(id));
CREATE TABLE recepcion_material_detalle(id INT AUTO_INCREMENT PRIMARY KEY,recepcion_id INT NOT NULL,material_id INT NOT NULL,cantidad_devuelta DECIMAL(12,2) NOT NULL,estado_material ENUM('Bueno','Usado','Dañado','Perdido') NOT NULL,stock_antes DECIMAL(12,2) NOT NULL,stock_despues DECIMAL(12,2) NOT NULL,FOREIGN KEY(recepcion_id) REFERENCES recepciones_materiales(id),FOREIGN KEY(material_id) REFERENCES materiales(id));
CREATE TABLE kardex_materiales(id INT AUTO_INCREMENT PRIMARY KEY,material_id INT NOT NULL,tipo_movimiento VARCHAR(40) NOT NULL,cantidad DECIMAL(12,2) NOT NULL,stock_antes DECIMAL(12,2) NOT NULL,stock_despues DECIMAL(12,2) NOT NULL,referencia_tipo VARCHAR(40),referencia_id INT,usuario_id INT,fecha DATETIME NOT NULL,FOREIGN KEY(material_id) REFERENCES materiales(id),FOREIGN KEY(usuario_id) REFERENCES usuarios(id),INDEX idx_kardex_fecha(fecha));
CREATE TABLE origenes_cable(id INT AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(120) NOT NULL UNIQUE,estado ENUM('activo','inactivo') DEFAULT 'activo',created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,deleted_at TIMESTAMP NULL);
CREATE TABLE marcas_cable(id INT AUTO_INCREMENT PRIMARY KEY,nombre VARCHAR(100) NOT NULL UNIQUE,estado ENUM('activo','inactivo') DEFAULT 'activo',created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,deleted_at TIMESTAMP NULL);
CREATE TABLE cables(id INT AUTO_INCREMENT PRIMARY KEY,numero_cable VARCHAR(80) NOT NULL UNIQUE,marca_id INT,calibre VARCHAR(80),tipo_enchufe VARCHAR(120),aislacion VARCHAR(120),largo DECIMAL(10,2),capacidad_aislacion VARCHAR(120),imagen VARCHAR(255),estado ENUM('disponible','en reparación','entregado','dado de baja') DEFAULT 'disponible',observacion TEXT,created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,deleted_at TIMESTAMP NULL,FOREIGN KEY(marca_id) REFERENCES marcas_cable(id),INDEX idx_cable_estado(estado));
CREATE TABLE informes_cable(id INT AUTO_INCREMENT PRIMARY KEY,supervisor_id INT,fecha_recepcion_cable DATE,fecha_entrega_cable DATE,cable_id INT NOT NULL,origen_cable VARCHAR(150),recepcion_numero_cable VARCHAR(80),recepcion_calibre VARCHAR(80),recepcion_tipo_enchufe VARCHAR(120),recepcion_aislacion VARCHAR(120),recepcion_largo VARCHAR(80),recepcion_capacidad_aislacion VARCHAR(120),recepcion_marca_cable VARCHAR(100),estado_informe ENUM('borrador','finalizado','anulado') DEFAULT 'borrador',rep_ing_mufas_termo INT DEFAULT 0,rep_ing_mufa_union INT DEFAULT 0,rep_ing_chaquetas INT DEFAULT 0,rep_sal_mufas_termo INT DEFAULT 0,rep_sal_mufa_union INT DEFAULT 0,rep_sal_chaquetas INT DEFAULT 0,estado_operativo VARCHAR(40),destino_cable VARCHAR(120),tipo_enchufe_entrega VARCHAR(120),largo_entrega VARCHAR(80),marca_entrega VARCHAR(100),capacidad_aislacion_entrega VARCHAR(120),fallas_chaquetas LONGTEXT,fallas_enchufe LONGTEXT,lugares_falla LONGTEXT,causas_probables LONGTEXT,pruebas_continuidad LONGTEXT,prueba_ez_thump LONGTEXT,continuidad_final LONGTEXT,vlf LONGTEXT,pruebas_finales LONGTEXT,observacion_final TEXT,creado_por INT,actualizado_por INT,created_at TIMESTAMP NULL,updated_at TIMESTAMP NULL,deleted_at TIMESTAMP NULL,FOREIGN KEY(supervisor_id) REFERENCES usuarios(id),FOREIGN KEY(cable_id) REFERENCES cables(id),FOREIGN KEY(creado_por) REFERENCES usuarios(id),FOREIGN KEY(actualizado_por) REFERENCES usuarios(id),INDEX idx_informe_fecha(fecha_recepcion_cable));
CREATE TABLE informe_fallas_chaquetas(id INT AUTO_INCREMENT PRIMARY KEY,informe_id INT,opcion VARCHAR(120),FOREIGN KEY(informe_id) REFERENCES informes_cable(id));
CREATE TABLE informe_fallas_enchufe(id INT AUTO_INCREMENT PRIMARY KEY,informe_id INT,opcion VARCHAR(120),FOREIGN KEY(informe_id) REFERENCES informes_cable(id));
CREATE TABLE informe_lugares_falla(id INT AUTO_INCREMENT PRIMARY KEY,informe_id INT,opcion VARCHAR(120),FOREIGN KEY(informe_id) REFERENCES informes_cable(id));
CREATE TABLE informe_causas_probables(id INT AUTO_INCREMENT PRIMARY KEY,informe_id INT,opcion VARCHAR(120),FOREIGN KEY(informe_id) REFERENCES informes_cable(id));
CREATE TABLE informe_materiales(id INT AUTO_INCREMENT PRIMARY KEY,informe_id INT NOT NULL,material_id INT NOT NULL,entrega_detalle_id INT,cantidad_utilizada DECIMAL(12,2) NOT NULL,stock_usuario_antes DECIMAL(12,2),stock_usuario_despues DECIMAL(12,2),FOREIGN KEY(informe_id) REFERENCES informes_cable(id),FOREIGN KEY(material_id) REFERENCES materiales(id),FOREIGN KEY(entrega_detalle_id) REFERENCES entrega_material_detalle(id));
CREATE TABLE informe_pruebas(id INT AUTO_INCREMENT PRIMARY KEY,informe_id INT NOT NULL,campo VARCHAR(80) NOT NULL,item VARCHAR(120) NOT NULL,realizada TINYINT(1) NOT NULL DEFAULT 0,con_falla TINYINT(1) NOT NULL DEFAULT 0,valor VARCHAR(80),unidad VARCHAR(40),FOREIGN KEY(informe_id) REFERENCES informes_cable(id),INDEX idx_informe_pruebas(informe_id,campo));
CREATE TABLE informe_datos(id INT AUTO_INCREMENT PRIMARY KEY,informe_id INT NOT NULL,campo VARCHAR(190) NOT NULL,valor LONGTEXT,FOREIGN KEY(informe_id) REFERENCES informes_cable(id),INDEX idx_informe_datos(informe_id,campo));
CREATE TABLE audit_logs(id INT AUTO_INCREMENT PRIMARY KEY,usuario_id INT,accion VARCHAR(80),modulo VARCHAR(80),registro_id INT,descripcion TEXT,ip VARCHAR(60),user_agent VARCHAR(255),fecha DATETIME NOT NULL,FOREIGN KEY(usuario_id) REFERENCES usuarios(id),INDEX idx_audit(fecha,modulo));
INSERT INTO roles(nombre,created_at) VALUES ('Super Administrador',NOW()),('Administrador',NOW()),('Supervisor',NOW()),('Técnico',NOW()),('Bodega',NOW()),('Visualizador',NOW());
INSERT INTO permisos(modulo,permiso) SELECT m,p FROM (SELECT 'Dashboard' m UNION SELECT 'Usuarios' UNION SELECT 'Roles' UNION SELECT 'Materiales' UNION SELECT 'Entrega de materiales' UNION SELECT 'Recepción de materiales' UNION SELECT 'Cables' UNION SELECT 'Informes de cable' UNION SELECT 'Marcas de cable' UNION SELECT 'Reportes' UNION SELECT 'Configuración' UNION SELECT 'Origen cable') mods JOIN (SELECT 'ver' p UNION SELECT 'crear' UNION SELECT 'editar' UNION SELECT 'eliminar' UNION SELECT 'exportar' UNION SELECT 'imprimir') perms;
INSERT INTO rol_permiso(rol_id,modulo,permiso,permitido) SELECT r.id,p.modulo,p.permiso,1 FROM roles r CROSS JOIN permisos p;
